downloadMeme.handler:
async function downloadMeme(args, ctx) {
  try {
    const size = 1080
    const canvas = document.createElement('canvas')
    canvas.width = size
    canvas.height = size
    const c = canvas.getContext('2d')

    // background
    c.fillStyle = '#A9D6A0'
    c.fillRect(0, 0, size, size)

    // load image (crossOrigin so canvas isn't tainted)
    const img = new Image()
    img.crossOrigin = 'anonymous'
    await new Promise((resolve, reject) => {
      img.onload = resolve
      img.onerror = reject
      img.src = args.imageUrl
    })

    // cover-fit the image into the full canvas
    const ratio = Math.max(size / img.width, size / img.height)
    const dw = img.width * ratio
    const dh = img.height * ratio
    const dx = (size - dw) / 2
    const dy = (size - dh) / 2
    c.drawImage(img, dx, dy, dw, dh)

    // text helper with outline
    function drawCaption(text, yBaseline) {
      if (!text) return
      let fontSize = 96
      c.textAlign = 'center'
      c.textBaseline = yBaseline === 'top' ? 'top' : 'bottom'
      c.font = '900 ' + fontSize + "px 'Nunito', sans-serif"
      // shrink to fit width
      while (c.measureText(text).width > size - 80 && fontSize > 30) {
        fontSize -= 4
        c.font = '900 ' + fontSize + "px 'Nunito', sans-serif"
      }
      const x = size / 2
      const y = yBaseline === 'top' ? 40 : size - 40
      c.lineWidth = Math.max(6, fontSize / 10)
      c.strokeStyle = '#20242A'
      c.lineJoin = 'round'
      c.strokeText(text.toUpperCase(), x, y)
      c.fillStyle = '#FFFFFF'
      c.fillText(text.toUpperCase(), x, y)
    }

    drawCaption(args.topText, 'top')
    drawCaption(args.bottomText, 'bottom')

    const dataUrl = canvas.toDataURL('image/png')
    const a = document.createElement('a')
    a.href = dataUrl
    a.download = args.fileName || 'meme.png'
    document.body.appendChild(a)
    a.click()
    document.body.removeChild(a)

    ctx.triggerActionEvent('done', {})
  } catch (e) {
    ctx.triggerActionEvent('error', { message: String(e) })
  }
}

blip.handler:
function blip(args, ctx) {
  try {
    const AudioCtx = window.AudioContext || window.webkitAudioContext
    if (!AudioCtx) return
    if (!window.__ufoAudioCtx) {
      window.__ufoAudioCtx = new AudioCtx()
    }
    const audio = window.__ufoAudioCtx
    if (audio.state === "suspended") {
      audio.resume()
    }
    const now = audio.currentTime
    const osc = audio.createOscillator()
    const gain = audio.createGain()
    const freq = typeof args.frequency === "number" && args.frequency > 0 ? args.frequency : 660
    osc.type = "sine"
    osc.frequency.setValueAtTime(freq, now)
    osc.frequency.exponentialRampToValueAtTime(freq * 1.5, now + 0.08)
    gain.gain.setValueAtTime(0.0001, now)
    gain.gain.exponentialRampToValueAtTime(0.12, now + 0.01)
    gain.gain.exponentialRampToValueAtTime(0.0001, now + 0.18)
    osc.connect(gain)
    gain.connect(audio.destination)
    osc.start(now)
    osc.stop(now + 0.2)
    ctx.triggerActionEvent("played", {})
  } catch (e) {
    // Audio not available; fail silently
  }
}

playBlip.handler:
function playBlip(args, ctx) {
  try {
    const w = typeof window !== "undefined" ? window : null;
    if (!w) return;
    const AC = w.AudioContext || w.webkitAudioContext;
    if (!AC) return;
    if (!w.__blipCtx) {
      w.__blipCtx = new AC();
    }
    const audio = w.__blipCtx;
    if (audio.state === "suspended") {
      audio.resume();
    }
    const freq = Number(args.frequency) || 440;
    const dur = Number(args.duration) || 0.12;
    const now = audio.currentTime;

    const osc = audio.createOscillator();
    const gain = audio.createGain();
    osc.type = "sine";
    osc.frequency.setValueAtTime(freq, now);
    osc.frequency.exponentialRampToValueAtTime(freq * 1.5, now + dur);

    gain.gain.setValueAtTime(0.0001, now);
    gain.gain.exponentialRampToValueAtTime(0.12, now + 0.01);
    gain.gain.exponentialRampToValueAtTime(0.0001, now + dur);

    osc.connect(gain);
    gain.connect(audio.destination);
    osc.start(now);
    osc.stop(now + dur + 0.02);
  } catch (e) {
    // audio is best-effort; ignore failures
  }
}
